SELECT TDS.ID TDS_ID, TDS.SCN TDS_SCN, TDS.SHIP_ID TDS_SHIP_ID, TDS.SHIP_NAME TDS_SHIP_NAME, TS.SHIP_NAME_EN TS_SHIP_NAME_EN, TDS.IMP_EXP TDS_IMP_EXP, TDS.TRADE_TYPE TDS_TRADE_TYPE, TDS.LOAD_UNLOAD TDS_LOAD_UNLOAD, TDS.IS_WATER TDS_IS_WATER, TDS.IS_SHORE_POWER TDS_IS_SHORE_POWER, TDS.REQ_WATER TDS_REQ_WATER, TDS.REQ_ELECTRICITY TDS_REQ_ELECTRICITY, TDS.BOW_DRAFT TDS_BOW_DRAFT, TDS.STERN_DRAFT TDS_STERN_DRAFT, TDS.IS_TUG TDS_IS_TUG, TDS.TUG_NUMBER TDS_TUG_NUMBER, TDS.PILOTAGE TDS_PILOTAGE, TDS.IS_PAYMENT TDS_IS_PAYMENT, TDS.PAYMENT_AMOUNT TDS_PAYMENT_AMOUNT, TDS.IS_DANGEROUS TDS_IS_DANGEROUS, TDS.ARRIVAL_TIME_PLAN TDS_ARRIVAL_TIME_PLAN, TDS.LEAVE_PORT_TIME_PLAN TDS_LEAVE_PORT_TIME_PLAN, TDS.LEAVE_PORT_TIME TDS_LEAVE_PORT_TIME, TDS.ARRIVAL_ANCHORAGE_TIME TDS_ARRIVAL_ANCHORAGE_TIME, TDS.LEAVE_ANCHORAGE_TIME TDS_LEAVE_ANCHORAGE_TIME, TDS.BERTH_TIME TDS_BERTH_TIME, TDS.BERTH_ID TDS_BERTH_ID, TDS.BERTH_NAME TDS_BERTH_NO, TDS.BERTH_TYPE TDS_BERTH_TYPE, TDS.BOLLARD_NO_START TDS_BOLLARD_NO_START, TDS.BOLLARD_NO_END TDS_BOLLARD_NO_END, TDS.LEAVE_BERTH_TIME TDS_LEAVE_BERTH_TIME, TDS.RECEIVE_BY TDS_RECEIVE_BY, TDS.RECEIVE_BY_NAME TDS_RECEIVE_BY_NAME, TDS.RECEIVE_TIME TDS_RECEIVE_TIME, TDS.DEL_FLAG TDS_DEL_FLAG, TDS.DEL_REMARK TDS_DEL_REMARK, TDS.DEL_BY TDS_DEL_BY, TDS.DEL_BY_NAME TDS_DEL_BY_NAME, TDS.DEL_TIME TDS_DEL_TIME, TDS.REMARK TDS_REMARK, TDS.CREATE_BY TDS_CREATE_BY, TDS.CREATE_BY_NAME TDS_CREATE_BY_NAME, TDS.CREATE_TIME TDS_CREATE_TIME, TDS.UPDATE_BY TDS_UPDATE_BY, TDS.UPDATE_BY_NAME TDS_UPDATE_BY_NAME, TDS.UPDATE_TIME TDS_UPDATE_TIME, TDS.START_PORT_ID TDS_START_PORT_ID, TDS.START_PORT_NAME TDS_START_PORT_NAME, TDS.END_PORT_ID TDS_END_PORT_ID, TDS.END_PORT_NAME TDS_END_PORT_NAME, TDS.PRE_PORT_ID TDS_PRE_PORT_ID, TDS.PRE_PORT_NAME TDS_PRE_PORT_NAME, TDS.NEXT_PORT_ID TDS_NEXT_PORT_ID, TDS.NEXT_PORT_NAME TDS_NEXT_PORT_NAME, TDS.SHIP_STATUS_CODE TDS_SHIP_STATUS_CODE, TDS.SHIP_STATUS_NAME TDS_SHIP_STATUS_NAME, TDS.CERTIFICATE_PATH TDS_CERTIFICATE_PATH, TDS.IS_START_WORK TDS_IS_START_WORK, TDS.IS_LAST_ARRIVAL_TYPE TDS_IS_LAST_ARRIVAL_TYPE, TDS.BERTHING_CHARGE TDS_BERTHING_CHARGE, TDS.JIESHOU_REMARK TDS_JIESHOU_REMARK, TS.CAPTAIN_PHONE TS_CAPTAIN_PHONE, TDS.WHARF TDS_WHARF, TS.HATCH_NUM SHIP_HATCH_NUM, TDS.CONFIRM_TIME TDS_CONFIRM_TIME, "IN".ID IN_ID, "IN".SHIPVOYAGE_ID IN_SHIPVOYAGE_ID, "IN".IMP_EXP IN_IMP_EXP, "IN".TRADE_TYPE IN_TRADE_TYPE, "IN".LOAD_UNLOAD IN_LOAD_UNLOAD, "IN".VOYAGE IN_VOYAGE, "IN".COMPANY_ID IN_COMPANY_ID, "IN".COMPANY_NAME IN_COMPANY_NAME, "IN".CARGO_CATEGORY_CODE IN_CARGO_CATEGORY_CODE, "IN".CARGO_CATEGORY_NAME IN_CARGO_CATEGORY_NAME, "IN".CARGO_NUM IN_CARGO_NUM, "IN".CUSTOMER_ID IN_CUSTOMER_ID, "IN".CUSTOMER_NAME IN_CUSTOMER_NAME, "IN".CONTACTS IN_CONTACTS, "IN".SHIP_PHONE IN_SHIP_PHONE, "IN".PAYMENT_AMOUNT IN_PAYMENT_AMOUNT, "IN".REMARK IN_REMARK, "IN".SHIP_STATUS_CODE IN_SHIP_STATUS_CODE, "IN".SHIP_STATUS_NAME IN_SHIP_STATUS_NAME, "IN".WORK_START_TIME IN_WORK_START_TIME, "IN".WORK_END_TIME IN_WORK_END_TIME, "IN".PRE_CHANGE_SHIP_NAME IN_PRE_CHANGE_SHIP_NAME, "IN".PRE_CHANGE_SHIP_NO IN_PRE_CHANGE_SHIP_NO, "OUT".ID OUT_ID, "OUT".SHIPVOYAGE_ID OUT_SHIPVOYAGE_ID, "OUT".IMP_EXP OUT_IMP_EXP, "OUT".TRADE_TYPE OUT_TRADE_TYPE, "OUT".LOAD_UNLOAD OUT_LOAD_UNLOAD, "OUT".VOYAGE OUT_VOYAGE, "OUT".COMPANY_ID OUT_COMPANY_ID, "OUT".COMPANY_NAME OUT_COMPANY_NAME, "OUT".CARGO_CATEGORY_CODE OUT_CARGO_CATEGORY_CODE, "OUT".CARGO_CATEGORY_NAME OUT_CARGO_CATEGORY_NAME, "OUT".CARGO_NUM OUT_CARGO_NUM, "OUT".CUSTOMER_ID OUT_CUSTOMER_ID, "OUT".CUSTOMER_NAME OUT_CUSTOMER_NAME, "OUT".CONTACTS OUT_CONTACTS, "OUT".SHIP_PHONE OUT_SHIP_PHONE, "OUT".PAYMENT_AMOUNT OUT_PAYMENT_AMOUNT, "OUT".REMARK OUT_REMARK, "OUT".SHIP_STATUS_CODE OUT_SHIP_STATUS_CODE, "OUT".SHIP_STATUS_NAME OUT_SHIP_STATUS_NAME, "OUT".WORK_START_TIME OUT_WORK_START_TIME, "OUT".WORK_END_TIME OUT_WORK_END_TIME FROM T_DIS_SHIPVOYAGE TDS LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "IN" ON ("IN".IMP_EXP = 'IN' AND TDS.ID = "IN".SHIPVOYAGE_ID) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "OUT" ON ("OUT".IMP_EXP = 'OUT' AND TDS.ID = "OUT".SHIPVOYAGE_ID) LEFT JOIN M_SHIP TS ON TS.ID = TDS.SHIP_ID
and ("IN".ID = #{shipVoyage, jdbcType=VARCHAR} OR "OUT".ID = #{shipVoyage, jdbcType=VARCHAR})
and TDS.ID = #{id, jdbcType=BIGINT}
and TDS.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
and TDS.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}
and TDS.IMP_EXP = #{impExp, jdbcType=VARCHAR}
and TDS.LOAD_UNLOAD = #{loadUnload, jdbcType=VARCHAR}
ORDER BY TDS.CREATE_TIME DESC

mapper.select:
SELECT
A.ID "shipvoyageItemId",
B.ID "shipvoyageId",
B.SHIP_NAME || '_' || A.VOYAGE "shipVoyage",
B.SCN "scn",
A.TRADE_TYPE "tradeType",
A.IMP_EXP "impExp",
A.LOAD_UNLOAD "loadUnload",
A.CARGO_CATEGORY_NAME "cargoName",
A.CUSTOMER_ID "customerId",
A.CUSTOMER_NAME "customerName",
A.COMPANY_NAME "companyName",
B.SHIP_STATUS_CODE "shipStatusCode",
B.SHIP_STATUS_NAME "shipStatusName"
FROM T_DIS_SHIPVOYAGE_ITEM A
LEFT JOIN T_DIS_SHIPVOYAGE B ON B.ID = A.SHIPVOYAGE_ID


        A.ID = #{shipvoyageItemId}



        AND B.SHIP_NAME LIKE #{shipName_like}



        AND A.VOYAGE LIKE #{voyage_like}


        AND A.TRADE_TYPE = #{tradeType}


        AND A.CUSTOMER_ID = #{customerId}


        AND B.SHIP_STATUS_CODE = #{shipStatusCode}


        AND A.IMP_EXP = #{impExp}


        AND A.LOAD_UNLOAD = #{loadUnload}


order by A.CREATE_TIME DESC nulls last

SELECT A.ID, A.SHIPVOYAGE_ID, A.SHIPVOYAGE_ITEM_ID, A.DELIVERY_NUMBERS, B.CARGO_INFO_NO, A.QUANTITY, A.TON, A.PACKING_CODE, A.PACKING_NAME, A.SPECS, A.PERMIT_THROUGH, A.REMARK, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME FROM T_BUS_DISPATCH_RELEASE A LEFT JOIN ( SELECT DISPATCH_RELEASE_ID, LISTAGG(CARGO_INFO_NO, ', ') WITHIN GROUP ( ORDER BY DISPATCH_RELEASE_ID) AS CARGO_INFO_NO FROM T_BUS_DISPATCH_RELEASE_DETAIL GROUP BY DISPATCH_RELEASE_ID ) B ON A.ID = B.DISPATCH_RELEASE_ID
A.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND A.DELIVERY_NUMBERS
#{item}

SELECT A.*,B.DELIVERY_NUMBERS
FROM T_BUS_TRUST A
LEFT JOIN T_BUS_TRUST_CARGO B ON A.ID = B.TRUST_ID

    A.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}


        AND B.DELIVERY_NUMBERS LIKE #{deliveryNumbersLike}

mapper.insert:
begin
INSERT INTO T_BUS_DISPATCH_RELEASE( ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, DELIVERY_NUMBERS, QUANTITY, TON, PACKING_CODE, PACKING_NAME, SPECS, PERMIT_THROUGH, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME )VALUES ( #{item.id, jdbcType=VARCHAR}, #{item.shipvoyageId, jdbcType=VARCHAR}, #{item.shipvoyageItemId, jdbcType=VARCHAR}, #{item.deliveryNumbers, jdbcType=VARCHAR}, #{item.quantity, jdbcType=VARCHAR}, #{item.ton, jdbcType=VARCHAR}, #{item.packingCode, jdbcType=VARCHAR}, #{item.packingName, jdbcType=VARCHAR}, #{item.specs, jdbcType=VARCHAR}, #{item.permitThrough, jdbcType=VARCHAR}, #{item.remark, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now} );
end;

begin
INSERT INTO T_BUS_DISPATCH_RELEASE_DETAIL( ID, DISPATCH_RELEASE_ID, DELIVERY_NUMBERS, CARGO_INFO_NO, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, PACKING_CODE, PACKING_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME )VALUES ( #{item.id, jdbcType=VARCHAR}, #{item.dispatchReleaseId, jdbcType=VARCHAR}, #{item.deliveryNumbers, jdbcType=VARCHAR}, #{item.cargoInfoNo, jdbcType=VARCHAR}, #{item.cargoOwnerId, jdbcType=VARCHAR}, #{item.cargoOwnerName, jdbcType=VARCHAR}, #{item.cargoCode, jdbcType=VARCHAR}, #{item.cargoName, jdbcType=VARCHAR}, #{item.quantity, jdbcType=VARCHAR}, #{item.ton, jdbcType=VARCHAR}, #{item.packingCode, jdbcType=VARCHAR}, #{item.packingName, jdbcType=VARCHAR}, #{item.remark, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now} );
end;

mapper.delete:
DELETE FROM T_BUS_DISPATCH_RELEASE WHERE ID = ( SELECT A.ID FROM T_BUS_DISPATCH_RELEASE A LEFT JOIN T_BUS_DISPATCH_RELEASE_DETAIL B ON A.ID = B.DISPATCH_RELEASE_ID
B.CARGO_INFO_NO IS NULL
AND A.ID = #{id}
)

